function doGet(e){
  var url = e.parameter.url; // grab the URL passed in
  var response = UrlFetchApp.fetch(decodeURIComponent(url),{ // fire off a GET request, set the header to json
    headers: { "Content-type" : "application/json" }
  });
  var data = JSON.parse(response.getContentText()); // grab the json data
  return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON); 
}
